 719 |         function addTouchStep() {
 720 |             const type = document.getElementById('next-step-type').value;
 721 |             let val = "";
 722 |             if (type === 'NAV') val = "BACK";
 723 |             else if (type === 'WAIT') val = "1000";
 724 |             
 725 |             let stepVal = "";
 726 |             if (type === 'INTENT') {
 727 |                 const target = prompt("TARGET TYPE: (activity / service / broadcast)", "activity");
 728 |                 if (!target) return;
 729 |                 const content = prompt("INTENT PAYLOAD:\nEnter URL/URI or full JSON configuration:", '{"action":"android.intent.action.VIEW","data":""}');
 730 |                 if (!content) return;
 731 | 
 732 |                 try {
 733 |                     // If they entered valid JSON, we merge the target in.
 734 |                     const parsed = JSON.parse(content);
 735 |                     parsed.target = target.toLowerCase();
 736 |                     stepVal = JSON.stringify(parsed);
 737 |                 } catch(e) {
 738 |                     // If it's just a string (like a URL), we wrap it into a valid Intent JSON.
 739 |                     stepVal = JSON.stringify({ target: target.toLowerCase(), data: content });
 740 |                 }
 741 |             } else {
 742 |                 stepVal = prompt(`Enter value for ${type}:`, val);
 743 |             }
 744 |             
 745 |             if (stepVal === null || stepVal === "") return;
 746 |             touchChain.push({ type, val: stepVal, delay: 200 });
 747 |             renderTouchChain();
 748 |         }
