1858 |         async function getFriendlyBlob(fullPath, originalName) {
1859 |             const { data, error } = await sb.storage.from('cortex-vault').createSignedUrl(fullPath, 60);
1860 |             if (error) throw error;
1861 | 
1862 |             const resp = await fetch(data.signedUrl);
1863 |             let buffer = await resp.arrayBuffer();
1864 |             let fileName = originalName;
1865 | 
1866 |             // 1. Decompress if GZIP
1867 |             if (fileName.toLowerCase().endsWith('.gz')) {
1868 |                 buffer = await decompressGzip(buffer);
1869 |                 fileName = fileName.slice(0, -3);
1870 |             }
1871 | 
1872 |             // 2. Decrypt if CTX
1873 |             if (fileName.toLowerCase().endsWith('.ctx')) {
1874 |                 buffer = await decryptCtx(buffer);
1875 |                 fileName = fileName.slice(0, -4) + ".json";
1876 |             }
1877 | 
1878 |             return { blob: new Blob([buffer]), name: fileName };
1879 |         }
