 808 |         function saveTrapToRegistry() {
 809 |             const id = document.getElementById('edit-trap-id').value || 'trap_' + Date.now();
 810 |             const newTrap = {
 811 |                 id: id,
 812 |                 label: document.getElementById('trap-reg-label').value.trim() || 'Unnamed Trap',
 813 |                 target: document.getElementById('trap-reg-target').value.trim(),
 814 |                 strict: document.getElementById('trap-reg-strict').checked,
 815 |                 method: document.getElementById('trap-reg-method').value,
 816 |                 timeout: document.getElementById('trap-reg-timeout').value,
 817 |                 dim: document.getElementById('trap-reg-dim').value,
 818 |                 html: document.getElementById('trap-reg-html').value.trim()
 819 |             };
 820 | 
 821 |             if (!newTrap.target) return toast("FINGERPRINT REQUIRED", "danger");
 822 | 
 823 |             const registry = JSON.parse(localStorage.getItem('cortex_trap_registry') || '[]');
 824 |             const existingIdx = registry.findIndex(t => t.id === id);
 825 |             
 826 |             if (existingIdx > -1) registry[existingIdx] = newTrap;
 827 |             else registry.push(newTrap);
 828 | 
 829 |             localStorage.setItem('cortex_trap_registry', JSON.stringify(registry));
 830 |             selectedTrapId = id;
 831 |             closeTrapEditor();
