1093 |         function formatLastSeen(dateStr) {
1094 |             const now = new Date();
1095 |             const past = new Date(dateStr);
1096 |             const diffMs = now - past;
1097 |             const diffSec = Math.floor(diffMs / 1000);
1098 |             const diffMin = Math.floor(diffSec / 60);
1099 |             const diffHr = Math.floor(diffMin / 60);
1100 | 
1101 |             if (diffSec < 90) return "ONLINE";
1102 |             if (diffMin < 60) return `${diffMin}m ago`;
1103 |             if (diffHr < 24) return `${diffHr}h ago`;
1104 |             return past.toLocaleDateString();
